SELECT user_id, SUM(amount) / NULLIF(COUNT(orders), 0) AS avg_order
FROM order_summary
GROUP BY user_id;

SELECT user_id
FROM orders
WHERE EXISTS (
  SELECT 1 FROM allowed_statuses a WHERE a.status = orders.status
);

SELECT product_id
FROM products
WHERE NOT EXISTS (
  SELECT 1 FROM discontinued d WHERE d.product_id = products.product_id
);

SELECT id
FROM logs
WHERE created_at >= date_trunc('day', NOW() AT TIME ZONE 'UTC');

SELECT user_id, MAX(score) AS best
FROM game_scores
GROUP BY user_id;

SELECT order_id
FROM orders
WHERE order_id = ANY ('{}'::int[]);

SELECT u.id, COALESCE(o.total, 0) AS total
FROM users u
LEFT JOIN LATERAL (
  SELECT total FROM orders WHERE user_id = u.id ORDER BY created_at DESC LIMIT 1
) o ON true;

SELECT data->'name' AS name_json
FROM events
WHERE data ? 'name';

